import html
import ipaddress
import re
import socket
import ssl
import urllib.error
import urllib.parse
import urllib.request
from typing import Dict, Optional

import certifi


# Reasonable defaults for a scraping service
_DEFAULT_TIMEOUT_SECONDS = 10
_MAX_BYTES = 2 * 1024 * 1024  # 2 MiB cap to reduce memory/DoS risk

# Minimal user agent; some sites reject default urllib UA
_USER_AGENT = "social-media-scraper/1.0 (+https://example.invalid)"


class FetchError(RuntimeError):
    """Raised when fetching or parsing a page fails."""


def _build_ssl_context() -> ssl.SSLContext:
    # As requested: certifi CA bundle
    return ssl.create_default_context(cafile=certifi.where())


def _is_ip_address(host: str) -> bool:
    try:
        ipaddress.ip_address(host)
        return True
    except ValueError:
        return False


def _is_disallowed_ip(ip: ipaddress._BaseAddress) -> bool:
    # Block common internal/unsafe destinations (SSRF mitigation)
    return any(
        [
            ip.is_private,
            ip.is_loopback,
            ip.is_link_local,
            ip.is_multicast,
            ip.is_reserved,
            ip.is_unspecified,
        ]
    )


