    if not host:
        raise ValueError("URL host is empty")

    # Normalize common localhost names
    lowered = host.strip().strip(".").lower()
    if lowered in {"localhost", "localhost.localdomain"}:
        raise ValueError("Refusing to fetch from localhost")

    # If host is already an IP, validate directly
    if _is_ip_address(lowered):
        ip = ipaddress.ip_address(lowered)
        if _is_disallowed_ip(ip):
            raise ValueError(f"Refusing to fetch from disallowed IP: {ip}")
        return

