            content_type = resp.headers.get("Content-Type", "")
            charset = _extract_charset(content_type)

            # Read at most _MAX_BYTES
            data = resp.read(_MAX_BYTES + 1)
            if len(data) > _MAX_BYTES:
                raise FetchError("Response too large")

            html_text = _decode_bytes(data, charset)

    except urllib.error.HTTPError as e:
        raise FetchError(f"HTTP error: {e.code}") from e
    except urllib.error.URLError as e:
        raise FetchError("Network error") from e
    except ssl.SSLError as e:
        raise FetchError("TLS/SSL error") from e
    except TimeoutError as e:
        raise FetchError("Request timed out") from e

    title = _extract_title(html_text)
    description = _extract_meta_description(html_text)

    return {
        "url": normalized_url,
        "title": title,
        "description": description,
    }

