# Conservative limits to reduce abuse potential
_DEFAULT_TIMEOUT_SECONDS = 10
_MAX_BYTES = 1_000_000  # 1 MB
_ALLOWED_SCHEMES = {"http", "https"}


class MetadataFetchError(RuntimeError):
