def _is_ip_address(host: str) -> bool:
    try:
        ipaddress.ip_address(host)
        return True
    except ValueError:
        return False


def _host_is_disallowed(host: str) -> bool:
    """
    SSRF hardening: disallow localhost and private/internal networks.

    This checks:
    - Literal IPs (v4/v6)
    - DNS-resolved IPs for hostnames
